using UnityEngine; [RequireComponent(typeof(Light))] public class BackroomsSectionLightFlicker : MonoBehaviour { public float baseIntensity = 5.4f; public float minIntensity = 0.35f; public float maxIntensity = 6.2f; public float flickerSpeed = 12f; public float pulseAmount = 0.55f; public float dropoutChancePerSecond = 0.2f; private Light targetLight; private float seed; private float dropoutTimer; private void Awake(){ targetLight = GetComponent<Light>(); seed = Random.Range(0f, 1000f); targetLight.intensity = baseIntensity; } private void Update(){ if (targetLight == null) return; if (dropoutTimer > 0f){ dropoutTimer -= Time.deltaTime; targetLight.intensity = minIntensity; return; } if (Random.value < dropoutChancePerSecond * Time.deltaTime){ dropoutTimer = Random.Range(0.08f, 0.45f); targetLight.intensity = minIntensity; return; } float noise = Mathf.PerlinNoise(seed, Time.time * flickerSpeed); float pulse = Mathf.Sin((Time.time + seed) * 2.2f) * 0.12f; float value = baseIntensity + (noise - 0.5f) * pulseAmount * 2f + pulse; targetLight.intensity = Mathf.Clamp(value, minIntensity, maxIntensity); } }